import{_ as o,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"13A. Consultation About Changes To Rosters Or Hours Of","description":"","frontmatter":{"title":"13A. Consultation About Changes To Rosters Or Hours Of","eba":"Allied Health Professionals 2021-2026","topics":["hours","rosters","consultation"]},"headers":[],"relativePath":"ebas/allied-health/consultation-disputes/13A-consultation-about-changes-to-rosters-or-hours-of.md","filePath":"ebas/allied-health/consultation-disputes/13A-consultation-about-changes-to-rosters-or-hours-of.md"}'),a={name:"ebas/allied-health/consultation-disputes/13A-consultation-about-changes-to-rosters-or-hours-of.md"};function n(i,e,l,h,u,p){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_13a-consultation-about-changes-to-rosters-or-hours-of" tabindex="-1">13A. Consultation About Changes To Rosters Or Hours Of <a class="header-anchor" href="#_13a-consultation-about-changes-to-rosters-or-hours-of" aria-label="Permalink to &quot;13A. Consultation About Changes To Rosters Or Hours Of&quot;">​</a></h1><p>Work This clause 13A applies where a change to regular rosters or ordinary hours of work (which may impact upon an Employee, particularly in relation to their family and caring responsibilities) does not constitute a change that must be consulted upon in accordance with <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a>.</p><p><strong>13A.1</strong> Without limiting the provisions of <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a>, where an Employer proposes to change an Employee’s regular roster or ordinary hours of work, the Employer must consult with the Employee or Employees affected and their representatives, if any, about the proposed change.</p><p><strong>13A.2</strong> The Employer must:</p><p><strong>(a)</strong> consider health and safety impacts including fatigue;</p><p><strong>(b)</strong> provide to the Employee or Employees affected and their representatives, if any, information about the proposed change (for example, information about the nature of the change to the Employee’s regular roster or ordinary hours of work and when that change is proposed to commence);</p><p><strong>(c)</strong> invite the Employee or Employees affected and their representatives, if any, to give their views about the impact of the proposed change (including any impact in relation to their family or caring responsibilities); and</p><p><strong>(d)</strong> give consideration to any views about the impact of the proposed change that is given by the Employee or Employees concerned and/or their representatives.</p><p><strong>13A.3</strong> The requirement to consult under this clause 13A does not apply where an Employee has irregular, sporadic, or unpredictable working hours.</p><p><strong>13A.4</strong> These provisions are to be read in conjunction with the terms of the engagement between the Employer and Employee, other Agreement provisions concerning the scheduling of work and notice requirements and nothing in this clause 13A overrides the provisions of any other clauses in this Agreement, for example <a href="/eba/ebas/allied-health/hours-of-work/50-roster.html">clause 50</a> (Rosters) or <a href="/eba/ebas/allied-health/hours-of-work/47-hours-of-work.html">clause 47</a> (Hours of Work).</p><p><strong>13A.5</strong> Any dispute regarding the obligations under this clause 13A will be dealt with under the Dispute Resolution Procedure at <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of this Agreement.</p><p>Plain language terms: consult, major workplace change.</p>',12)])])}const g=o(a,[["render",n]]);export{d as __pageData,g as default};
